INSERT INTO public.intelligence_insights (id, company_id, generated_at, category, severity, headline, finding, recommendation, projected_impact, supporting_bids, status) VALUES ('340c21b2-48a7-4784-b34f-5769d5d88284', '00000000-0000-0000-0000-000000000001', '2026-05-11 19:55:36.449485+00', 'capacity', 'high', 'Hold firm on top open EIFS quote — schedule is 82% full', 'Average utilization across the next 4 weeks is 82%. The highest-value open quote is the EIFS package; discounting to win is not necessary based on current schedule.', 'Hold target price on top open quote.', '~$8,200 retained margin vs typical 5% schedule-discount', NULL, 'open');
INSERT INTO public.intelligence_insights (id, company_id, generated_at, category, severity, headline, finding, recommendation, projected_impact, supporting_bids, status) VALUES ('851801f1-ab5b-4e54-a20b-1979f51b08ab', '00000000-0000-0000-0000-000000000001', '2026-05-11 19:55:36.452328+00', 'margin', 'medium', 'EIFS delivered margin trending down 6pp vs target over last 8 jobs', 'Average delivered margin on EIFS jobs is 26.4% vs target 32%. 3 of last 4 EIFS jobs ran labor hours 12-18% over quote. ADEX-system install productivity assumption appears to need recalibration.', 'Add +12% labor hour buffer on next 3 EIFS quotes; measure outcomes.', 'Recover ~$4,800 margin per $100K EIFS revenue if formula updated', NULL, 'open');
INSERT INTO public.intelligence_insights (id, company_id, generated_at, category, severity, headline, finding, recommendation, projected_impact, supporting_bids, status) VALUES ('d85858a4-81a1-4f45-adc2-80eb1e915c34', '00000000-0000-0000-0000-000000000001', '2026-05-11 19:55:36.454067+00', 'exclusions', 'medium', '2 of 8 recent stucco-conventional quotes missed rough-grade exclusion', 'Both of those jobs incurred scope creep (+18% and +22% labor). Composition agent''s exclusions enforcement should auto-flag this exclusion on every stucco-conventional quote.', 'Enable enforcement of ''Rough grade should not be above final grade height'' for STUCCO-CONVENTIONAL service line.', 'Prevents 18-22% labor overruns on affected jobs', NULL, 'open');
INSERT INTO public.intelligence_insights (id, company_id, generated_at, category, severity, headline, finding, recommendation, projected_impact, supporting_bids, status) VALUES ('e6469872-8c37-41f9-81b5-b9443caa7255', '00000000-0000-0000-0000-000000000001', '2026-05-11 19:55:36.455455+00', 'competitor', 'low', 'Inex Plastering won 3 of last 5 EIFS bids you lost', 'Average winning bid in those losses was 9.4% below your quote. Pattern: Inex appears willing to price aggressively on EIFS.', 'When EIFS schedule utilization is <60%, consider matching Inex by 5-7% on shortlisted EIFS bids; otherwise hold.', '1-2 additional EIFS wins per quarter in low-utilization windows', NULL, 'open');
INSERT INTO public.intelligence_insights (id, company_id, generated_at, category, severity, headline, finding, recommendation, projected_impact, supporting_bids, status) VALUES ('81a7cc91-ad93-464f-a97e-b546dda3846b', '00000000-0000-0000-0000-000000000001', '2026-05-11 19:55:36.456889+00', 'follow_up', 'info', 'Repeat-customer single-touch follow-up has 73% response rate', 'Of 22 SENT bids to repeat clients in the last 6 months, the 5-day soft follow-up surfaced a decision in 16 cases (73%).', 'Continue the single-touch repeat cadence; do not escalate.', 'Avoids relationship damage; cadence is working', NULL, 'open');
