INSERT INTO public.service_lines (id, company_id, line_name, typical_scope_text, standard_exclusions, pricing_unit, pricing_range_residential, pricing_range_commercial, typical_margin_pct, manufacturers_referenced, last_extracted_at) VALUES ('d4e694e5-f5ce-42fa-b7f0-7e4e9fe423ab', '00000000-0000-0000-0000-000000000001', 'STUCCO-CONVENTIONAL', 'Three-coat conventional stucco system applied over metal lath and weather-resistive barrier. Includes scratch, brown, and finish coats to manufacturer specifications.', '{"Rough grade should not be above final grade height","Painting and waterproof coatings beyond integral color","Caulking of dissimilar material joints (by GC or others)","Sheet metal flashings, drip caps, and weep screeds (by others unless noted)","Permits, fees, and engineering","Final grading, landscaping, and irrigation","Repair of damage caused by other trades"}', 'per_sqft', '{"low": 12, "mid": 16, "high": 22}', '{"low": 14, "mid": 18, "high": 26}', 32.00, '{"BMI Products",ADEX,Sto}', '2026-05-11 19:55:35.435269+00');
