INSERT INTO public.service_lines (id, company_id, line_name, typical_scope_text, standard_exclusions, pricing_unit, pricing_range_residential, pricing_range_commercial, typical_margin_pct, manufacturers_referenced, last_extracted_at) VALUES ('cf572dcd-7afa-4a4b-b950-5f59b2c41231', '00000000-0000-0000-0000-000000000001', 'EIFS', 'Exterior Insulation and Finish System (EIFS) per ADEX system specification. Includes adhesive, EPS insulation, base coat with reinforcing mesh, and acrylic finish coat.', '{"Rough grade should not be above final grade height","Substrate preparation beyond cleaning and minor patching","Sealants between dissimilar materials (by others)","Sheet metal flashings (by others)","Painting beyond integral finish color","Permits, engineering, and design","Repair of damage from other trades or weather events"}', 'per_sqft', '{"low": 18, "mid": 24, "high": 32}', '{"low": 22, "mid": 28, "high": 38}', 30.00, '{ADEX,Sto,Dryvit}', '2026-05-11 19:55:35.43998+00');
INSERT INTO public.service_lines (id, company_id, line_name, typical_scope_text, standard_exclusions, pricing_unit, pricing_range_residential, pricing_range_commercial, typical_margin_pct, manufacturers_referenced, last_extracted_at) VALUES ('86ed5a3c-2b0c-4221-81e0-a31ca034c9f2', '00000000-0000-0000-0000-000000000001', 'Siding', 'Fiber cement or metal siding installation per manufacturer spec. Includes underlayment, trim, and fasteners per specification.', '{"Painting (by others unless pre-finished product specified)","Sheet metal flashings beyond manufacturer-supplied trim","Caulking between siding and dissimilar materials","Substrate repair beyond minor patching","Permits and inspections","Insulation and weather-resistive barrier (by others)"}', 'per_sqft', '{"low": 9, "mid": 13, "high": 18}', '{"low": 11, "mid": 15, "high": 22}', 28.00, '{"James Hardie",Gentek,LUX}', '2026-05-11 19:55:35.441854+00');
