INSERT INTO public.service_lines (id, company_id, line_name, typical_scope_text, standard_exclusions, pricing_unit, pricing_range_residential, pricing_range_commercial, typical_margin_pct, manufacturers_referenced, last_extracted_at) VALUES ('5fe99039-c352-4891-9c30-2d69e46176ce', '00000000-0000-0000-0000-000000000001', 'RESTUCCO', 'Re-stucco existing surfaces. Includes surface preparation, repair of cracks and spalling, and application of new finish coat.', '{"Removal and replacement of existing stucco beyond noted areas","Painting beyond integral color finish","Structural repair of substrate","Sheet metal flashings","Permits and engineering"}', 'per_sqft', '{"low": 7, "mid": 10, "high": 14}', '{"low": 8, "mid": 12, "high": 16}', 36.00, '{"BMI Products",ADEX}', '2026-05-11 19:55:35.44569+00');
INSERT INTO public.service_lines (id, company_id, line_name, typical_scope_text, standard_exclusions, pricing_unit, pricing_range_residential, pricing_range_commercial, typical_margin_pct, manufacturers_referenced, last_extracted_at) VALUES ('29481e93-610a-4a9b-b6e9-3222b1a3b965', '00000000-0000-0000-0000-000000000001', 'REPAIR', 'Patch and repair of stucco / EIFS / siding surfaces. Time-and-materials or lump-sum per scope. Color match where possible.', '{"Exact color matching of weathered substrates","Painting of repaired areas (by others)","Underlying water damage repair beyond noted scope",Permits}', 'lump_sum', '{"low": 1500, "mid": 4500, "high": 12000}', '{"low": 2500, "mid": 8000, "high": 25000}', 38.00, '{"BMI Products"}', '2026-05-11 19:55:35.44733+00');
INSERT INTO public.service_lines (id, company_id, line_name, typical_scope_text, standard_exclusions, pricing_unit, pricing_range_residential, pricing_range_commercial, typical_margin_pct, manufacturers_referenced, last_extracted_at) VALUES ('969ada2a-5982-4fd6-995a-a4c1850d93f6', '00000000-0000-0000-0000-000000000001', 'DEMOLITION', 'Selective demolition of existing wall systems for replacement. Includes removal, debris bin, and haul-away.', '{"Hazardous material abatement (asbestos, lead — by others)","Structural demolition or load-bearing element removal","Disposal fees for hazardous materials","Permits and notifications","Cleaning of adjacent areas"}', 'per_sqft', '{"low": 3, "mid": 5, "high": 8}', '{"low": 4, "mid": 6, "high": 10}', 30.00, '{}', '2026-05-11 19:55:35.449083+00');
INSERT INTO public.service_lines (id, company_id, line_name, typical_scope_text, standard_exclusions, pricing_unit, pricing_range_residential, pricing_range_commercial, typical_margin_pct, manufacturers_referenced, last_extracted_at) VALUES ('bbcb8e4a-1787-4656-bc4d-2d2a8caa3bd3', '00000000-0000-0000-0000-000000000002', 'INTERIOR-DOORS', 'Pre-hung interior door assemblies with jamb, casing, and stop. Standard core (hollow or solid as specified). Pre-finished.', '{"Hardware (knobs, hinges, latches) — by others unless noted","Field installation — supply only unless install line added","Door bottoms / weatherstripping","Custom finishes beyond standard catalog options","Painting at job site"}', 'lump_sum', '{"low": 220, "mid": 380, "high": 720}', '{"low": 350, "mid": 550, "high": 1200}', 28.00, '{Masonite,JELD-WEN,Trustile}', '2026-05-11 19:55:36.481664+00');
INSERT INTO public.service_lines (id, company_id, line_name, typical_scope_text, standard_exclusions, pricing_unit, pricing_range_residential, pricing_range_commercial, typical_margin_pct, manufacturers_referenced, last_extracted_at) VALUES ('607d4955-979d-4c05-b320-f5272bd7fd99', '00000000-0000-0000-0000-000000000002', 'CUSTOM-CABINETRY', 'Shop-built custom cabinets per drawings supplied. Standard construction unless noted: 3/4 ply box, 5-piece raised panel door, soft-close hardware.', '{"Counter tops — by others","Field measurements — based on drawings supplied","Plumbing, electrical, and appliance cutouts — by installer","Field installation — supply only unless install line added","Stone, tile, or backsplash work","Hardware beyond Blum soft-close hinges and drawer slides"}', 'per_lf', '{"low": 220, "mid": 380, "high": 580}', '{"low": 280, "mid": 480, "high": 850}', 32.00, '{Blum,Hafele,Wilsonart}', '2026-05-11 19:55:36.483303+00');
INSERT INTO public.service_lines (id, company_id, line_name, typical_scope_text, standard_exclusions, pricing_unit, pricing_range_residential, pricing_range_commercial, typical_margin_pct, manufacturers_referenced, last_extracted_at) VALUES ('ace5e9dd-3ea9-4487-a397-5eb5e9486b7b', '00000000-0000-0000-0000-000000000002', 'BASE-CASING', 'Base, casing, and chair rail trim packages. Pre-primed MDF or solid wood per spec. Standard profiles from catalog.', '{"Field installation — supply only unless install line added","Custom profiles beyond catalog","Stain / paint finishing at job site","Caulking and putty filling"}', 'per_lf', '{"low": 2.8, "mid": 4.5, "high": 7.5}', '{"low": 3.5, "mid": 5.5, "high": 9.0}', 25.00, '{Metrie,"Windsor One"}', '2026-05-11 19:55:36.48633+00');
INSERT INTO public.service_lines (id, company_id, line_name, typical_scope_text, standard_exclusions, pricing_unit, pricing_range_residential, pricing_range_commercial, typical_margin_pct, manufacturers_referenced, last_extracted_at) VALUES ('edb8feee-cc40-4f27-b39d-500dbdc06352', '00000000-0000-0000-0000-000000000002', 'ARCHITECTURAL-PANELS', 'Wall panel systems, custom millwork ceiling features, and feature-wall assemblies. CNC and shop-finished per drawings.', '{"Field installation — supply only unless install line added","Substrate / blocking — by GC","Lighting integration beyond pre-routed channels","Custom finishes beyond standard catalog options","Acoustic backing materials"}', 'per_sqft', '{"low": 42, "mid": 68, "high": 110}', '{"low": 52, "mid": 85, "high": 145}', 38.00, '{9Wood,Decoustics,"Hunter Douglas"}', '2026-05-11 19:55:36.484839+00');
INSERT INTO public.service_lines (id, company_id, line_name, typical_scope_text, standard_exclusions, pricing_unit, pricing_range_residential, pricing_range_commercial, typical_margin_pct, manufacturers_referenced, last_extracted_at) VALUES ('72302c63-8230-47a6-862d-9b711f8ef156', '00000000-0000-0000-0000-000000000003', 'BRAND-IDENTITY', 'Brand identity engagement covering positioning, naming (if needed), logo system, visual language, and brand guidelines.', '{"Trademark registration — handled by your legal counsel","Custom photography — quoted separately if needed","Web design and development","Print production and merchandising"}', 'lump_sum', NULL, '{"low": 28000, "mid": 55000, "high": 120000}', 55.00, '{}', '2026-05-11 19:55:36.770032+00');
INSERT INTO public.service_lines (id, company_id, line_name, typical_scope_text, standard_exclusions, pricing_unit, pricing_range_residential, pricing_range_commercial, typical_margin_pct, manufacturers_referenced, last_extracted_at) VALUES ('d52dc5fe-5677-4824-8c70-efdf02b1d3bd', '00000000-0000-0000-0000-000000000003', 'ONGOING-RETAINER', 'Monthly retainer for ongoing brand and marketing support. Hours allocated; specific work scoped each month.', '{"Paid media spend (ad budget separate)","Production costs beyond strategy and creative","Hours beyond retainer billed at $185/hr"}', 'hourly', NULL, '{"low": 6500, "mid": 12000, "high": 22000}', 60.00, '{}', '2026-05-11 19:55:36.773135+00');
INSERT INTO public.service_lines (id, company_id, line_name, typical_scope_text, standard_exclusions, pricing_unit, pricing_range_residential, pricing_range_commercial, typical_margin_pct, manufacturers_referenced, last_extracted_at) VALUES ('7febe61d-237d-4fda-ba4c-bea2e5f09a4f', '00000000-0000-0000-0000-000000000003', 'WEBSITE-PROJECT', 'Website strategy, design, and build. CMS-based (Webflow or WordPress) or static (Next.js) per requirements.', '{"Hosting and ongoing maintenance — separate retainer if desired","Ongoing content production beyond initial launch content","Custom CMS development beyond agreed scope","E-commerce setup unless explicitly included"}', 'lump_sum', NULL, '{"low": 18000, "mid": 42000, "high": 95000}', 50.00, '{Webflow,WordPress,Next.js}', '2026-05-11 19:55:36.771546+00');
INSERT INTO public.voice_patterns (id, company_id, tone, avg_sentence_length, preferred_terms, avoided_terms, boilerplate_intro, boilerplate_scope_intro, boilerplate_terms, boilerplate_warranty, boilerplate_closing, formatting, voice_embedding, source_document_ids, last_extracted_at) VALUES ('67aab775-31bc-4a81-89cc-7fc7cb80f21f', '00000000-0000-0000-0000-000000000001', 'direct, professional, no-nonsense; reads like a foreman wrote it', 17, '{"scope": ["scope of work", "work to be performed"], "client": ["owner", "general contractor"], "exclusions": ["the following are excluded", "we exclude"]}', '{partner,synergy,deliverable,leverage}', 'Thank you for the opportunity to provide a quote on this project. We are pleased to offer the following based on the scope and drawings supplied.', 'Our scope of work consists of the following:', 'Pricing is valid for 30 days from the date of this quote. Net 30 from invoice unless otherwise agreed. Progress draws available on jobs exceeding 4 weeks.', 'All workmanship is warranted for one year from substantial completion. Material warranties pass through from manufacturer.', 'Please call with any questions. We appreciate the opportunity and look forward to working with you.', '{"section_headers": true, "all_caps_emphasis": false, "uses_bullet_points": true}', NULL, NULL, '2026-05-11 19:55:35.431233+00');
INSERT INTO public.voice_patterns (id, company_id, tone, avg_sentence_length, preferred_terms, avoided_terms, boilerplate_intro, boilerplate_scope_intro, boilerplate_terms, boilerplate_warranty, boilerplate_closing, formatting, voice_embedding, source_document_ids, last_extracted_at) VALUES ('ba7d4b3d-9e66-45ea-b83d-3993a5cc4e6c', '00000000-0000-0000-0000-000000000002', 'precise, technical, catalog-oriented; reads like a shop foreman wrote it', 14, '{"scope": ["work to be performed", "items quoted"], "client": ["builder", "owner"], "exclusions": ["not included in this quote"]}', '{partnership,ecosystem,stakeholder}', 'Thank you for the opportunity. Please find our quote below for the millwork items as described in your request.', 'Items quoted:', 'Quote valid 30 days. 50% deposit on order, balance net 30 from delivery. Custom items non-refundable once production starts.', 'Millwork warranted against manufacturer defect for one year from delivery. Field damage and finish wear are not covered.', 'Please review and confirm. We''ll begin production upon receipt of signed approval and deposit.', '{"section_headers": true, "all_caps_emphasis": true, "uses_bullet_points": false, "uses_line_item_table": true}', NULL, NULL, '2026-05-11 19:55:36.480076+00');
INSERT INTO public.voice_patterns (id, company_id, tone, avg_sentence_length, preferred_terms, avoided_terms, boilerplate_intro, boilerplate_scope_intro, boilerplate_terms, boilerplate_warranty, boilerplate_closing, formatting, voice_embedding, source_document_ids, last_extracted_at) VALUES ('e9cab484-3977-45dc-92ab-92efb11e29ef', '00000000-0000-0000-0000-000000000003', 'warm, story-first, plain-language; reads like a strategist wrote it', 19, '{"scope": ["work", "engagement"], "client": ["client", "team"], "exclusions": ["what''s not included"]}', '{leverage,synergy,deliverable,stakeholder,robust}', 'Thanks for the conversation last week — really enjoyed digging into what you''re trying to build. Here''s how we''d approach the work.', 'Here''s what we''d do for you:', 'Engagement starts on signed agreement and 50% deposit. Balance due on project completion. Two rounds of revision per phase included; additional rounds billed at $185/hr.', '', 'We''d love to work on this with you. Reply when you''re ready and we''ll send over the agreement.', '{"section_headers": true, "all_caps_emphasis": false, "uses_bullet_points": true, "uses_narrative_paragraphs": true}', NULL, NULL, '2026-05-11 19:55:36.768527+00');
